const fontForWord = (str) => {
  const n = [...(str || "")].length;
  if (n <= 2) return 66;
  if (n <= 3) return 54;
  if (n <= 5) return 42;
  if (n <= 7) return 32;
  return 26;
};

/* ============================ clipboard =================================== */
function fallbackCopy(t) {
  try {
    const ta = document.createElement("textarea");
    ta.value = t;
    ta.style.position = "fixed";
    ta.style.top = "-9999px";
    ta.style.opacity = "0";
    ta.style.webkitUserSelect = "text"; // body sets user-select:none for app feel
    ta.style.userSelect = "text";
    ta.setAttribute("readonly", "");
    document.body.appendChild(ta);
    ta.focus();
    ta.select();
    document.execCommand("copy");
    document.body.removeChild(ta);
  } catch (e) {}
}
function copyText(t) {
  try {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(t).catch(() => fallbackCopy(t));
      return;
    }
  } catch (e) {}
  fallbackCopy(t);
}
// read the clipboard (returns the text, or null if the browser blocks/refuses access)
async function readClipboard() {
  try {
    if (navigator.clipboard && navigator.clipboard.readText) {
      return await navigator.clipboard.readText();
    }
  } catch (e) {}
  return null;
}

/* subtle haptic tick (mobile) — silently ignored where unsupported */
function haptic(ms) {
  try {
    if (typeof navigator !== "undefined" && navigator.vibrate) navigator.vibrate(ms);
  } catch (e) {}
}

/* ============================ component =================================== */
export default function JlptN5Srs() {
  const [ready, setReady] = useState(false);
  const [view, setView] = useState("home"); // 'home' | 'study'
  const [scope, setScope] = useState({ type: "all" });
  const [sched, setSched] = useState({});
  const [daily, setDaily] = useState({ date: todayStr(Date.now()), newDone: 0, reviewsToday: 0, extraNew: 0 });
  const [settings, setSettings] = useState({ direction: "jp", newPerDay: 15 });
  const [theme, setTheme] = useState("dark"); // 'dark' | 'light' | 'auto'
  const [sysLight, setSysLight] = useState(false);
  const [now, setNow] = useState(Date.now());
  const [cur, setCur] = useState(null); // {id,isNew,dir}
  const [revealed, setRevealed] = useState(false);
  const [undoStack, setUndoStack] = useState([]);
  const [toast, setToast] = useState(null);
  const [flash, setFlash] = useState(null);
  const [activeGrade, setActiveGrade] = useState(-1);
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [homeMode, setHomeMode] = useState("level"); // 'level' | 'revision'
  const [sortMode, setSortMode] = useState("section"); // card order within a scope: 'section' (deck order) | 'freq' (most common first)
  const [confirmRevReset, setConfirmRevReset] = useState(false);
  const [revKnown, setRevKnown] = useState({}); // { cardId: true } — revision "got it" set
  const [revSched, setRevSched] = useState({}); // revision's OWN SRS schedule, independent of By-level `sched`
  const [revQueue, setRevQueue] = useState([]); // captured ordered card ids for the current revision session (flip mode only)
  const [revPos, setRevPos] = useState(0); // pointer into the current revision queue
  const [revMode, setRevMode] = useState("srs"); // revision answer mode: 'srs' = Anki grades (default) · 'flip' = Got it/Again
  const [bdEdits, setBdEdits] = useState({}); // { cardId: markdownString } — user-edited breakdowns, global across all scopes
  const [editing, setEditing] = useState(null); // cardId currently open in the breakdown editor, or null
  const [syncTs, setSyncTs] = useState(0); // timestamp of this device's data (for last-write-wins cloud sync)
  const [syncOn, setSyncOn] = useState(true); // auto-sync across devices
  const [syncState, setSyncState] = useState("idle"); // idle | syncing | ok | err
  const syncTsRef = useRef(0);
  const lastPushedJsonRef = useRef(null);
  const initialPullDoneRef = useRef(false);
  const toastTimer = useRef(null);

  /* ---- hydrate state data (used by initial load + cross-device import) ---- */
  function applyData(s) {
    if (!s) return;
    s = stripOldN3(s); // data saved before the N3 deck replacement: drop keys that point at the old N3 cards
    if (s.sched) setSched(s.sched);
    if (s.settings) setSettings((p) => ({ ...p, ...s.settings }));
    if (s.theme) setTheme(s.theme);
    if (s.daily) {
      const d = s.daily;
      if (d.date !== todayStr(Date.now())) setDaily({ date: todayStr(Date.now()), newDone: 0, reviewsToday: 0, extraNew: 0 });
      else setDaily({ extraNew: 0, ...d });
    }
    if (s.homeMode) setHomeMode(s.homeMode);
    if (s.revMode) setRevMode(s.revMode);
    if (s.sortMode) setSortMode(s.sortMode);
    if (s.bdEdits) setBdEdits(s.bdEdits);
    if (s.revKnown) setRevKnown(s.revKnown);
    if (s.revSched) setRevSched(s.revSched);
  }

  /* ---- merge remote cloud data: replace progress, UNION notes & known-marks (never drop a note) ---- */
  function applyRemote(data) {
    if (!data) return;
    data = stripOldN3(data); // a device still on the old deck may push old-revision data
    if (data.sched) setSched(data.sched);
    if (data.settings) setSettings((p) => ({ ...p, ...data.settings }));
    if (data.theme) setTheme(data.theme);
    if (data.daily) {
      const d = data.daily;
      if (d.date !== todayStr(Date.now())) setDaily({ date: todayStr(Date.now()), newDone: 0, reviewsToday: 0, extraNew: 0 });
      else setDaily({ extraNew: 0, ...d });
    }
    if (data.homeMode) setHomeMode(data.homeMode);
    if (data.revMode) setRevMode(data.revMode);
    if (data.sortMode) setSortMode(data.sortMode);
    if (data.revKnown) setRevKnown(data.revKnown); // replace (LWW) so a reset propagates; notes stay unioned below
    if (data.revSched) setRevSched(data.revSched); // replace (LWW) so a revision reset propagates
    if (data.bdEdits) setBdEdits((p) => ({ ...p, ...data.bdEdits }));
  }
  useEffect(() => {
    syncTsRef.current = syncTs;
  }, [syncTs]);

  async function pullCloud() {
    if (!syncOn) return;
    try {
      setSyncState("syncing");
      const r = await fetch(CLOUD_URL + "/api/state?room=" + CLOUD_ROOM, { cache: "no-store" });
      const j = await r.json();
      if (j && j.data && Number(j.ts) > syncTsRef.current) {
        lastPushedJsonRef.current = JSON.stringify(j.data);
        applyRemote(j.data);
        const ts = Number(j.ts);
        syncTsRef.current = ts;
        setSyncTs(ts);
      }
      setSyncState("ok");
    } catch (e) {
      setSyncState("err");
    } finally {
      initialPullDoneRef.current = true;
    }
  }
  async function pushCloud(blob, ts, json) {
    if (!syncOn) return;
    try {
      setSyncState("syncing");
      const r = await fetch(CLOUD_URL + "/api/state?room=" + CLOUD_ROOM, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ts, data: blob }),
      });
      await r.json();
      lastPushedJsonRef.current = json;
      setSyncState("ok");
    } catch (e) {
      setSyncState("err");
    }
  }

  /* ---- load once (restore progress + last screen + theme) ---- */
  useEffect(() => {
    (async () => {
      const s = await loadState();
      if (s) {
        applyData(s);
        if (typeof s.syncTs === "number") { setSyncTs(s.syncTs); syncTsRef.current = s.syncTs; }
        if (typeof s.syncOn === "boolean") setSyncOn(s.syncOn);
        // restore the screen the user was last on
        const merged = s.scope && s.scope.type === "merged";
        if (s.scope && !merged) setScope(s.scope);
        if (merged) {
          // don't restore mid-revision-session; return to the revision home
          setHomeMode("revision");
        } else if (s.view === "study") {
          setView("study");
          if (s.cur && CARD_BY_ID[s.cur.id]) {
            setCur(s.cur);
            setRevealed(!!s.revealed);
          }
        }
      }
      setReady(true);
    })();
  }, []);

  /* ---- system colour-scheme (for theme:'auto') ---- */
  useEffect(() => {
    if (typeof window === "undefined" || !window.matchMedia) return;
    const mq = window.matchMedia("(prefers-color-scheme: light)");
    const on = () => setSysLight(!!mq.matches);
    on();
    if (mq.addEventListener) mq.addEventListener("change", on);
    else if (mq.addListener) mq.addListener(on);
    return () => {
      if (mq.removeEventListener) mq.removeEventListener("change", on);
      else if (mq.removeListener) mq.removeListener(on);
    };
  }, []);

  /* ---- apply theme to <html> + browser chrome ---- */
  const effTheme = theme === "auto" ? (sysLight ? "light" : "dark") : theme;
  useEffect(() => {
    if (typeof document === "undefined") return;
    document.documentElement.setAttribute("data-theme", effTheme);
    const m = document.querySelector('meta[name="theme-color"]');
    if (m) m.setAttribute("content", THEME_BG[effTheme] || THEME_BG.dark);
  }, [effTheme]);

  /* ---- clock tick ---- */
  useEffect(() => {
    const t = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(t);
  }, []);

  /* ---- midnight rollover ---- */
  useEffect(() => {
    if (!ready) return;
    const t = todayStr(now);
    if (daily.date !== t) setDaily({ date: t, newDone: 0, reviewsToday: 0, extraNew: 0 });
  }, [now, ready, daily.date]);

  /* ---- persist progress + last screen + theme ---- */
  useEffect(() => {
    if (!ready) return;
    saveState({ v: 1, deckRev: DECK_REV, sched, daily, settings, theme, view, scope, cur, revealed, homeMode, revMode, sortMode, revKnown, revSched, bdEdits, syncTs, syncOn });
  }, [sched, daily, settings, theme, view, scope, cur, revealed, homeMode, revMode, sortMode, revKnown, revSched, bdEdits, syncTs, syncOn, ready]);

  /* ---- scope cards (optionally re-ordered most-frequent-first) ---- */
  const scopeCards = useMemo(() => {
    const list =
      scope.type === "all"
        ? CARDS
        : scope.type === "level"
        ? CARDS.filter((c) => c.level === scope.level)
        : scope.type === "merged"
        ? (scope.mg === -1 ? MERGED.flatMap((g) => g.ids) : MERGED[scope.mg].ids).map((id) => CARD_BY_ID[id])
        : CARDS.filter((c) => c.si === scope.si);
    // "freq" mode orders cards by corpus frequency (most common first) so the highest-value
    // words are introduced/seen first. Applies to study AND revision.
    if (sortMode === "freq") {
      return list
        .map((c, i) => [c, i])
        .sort((a, b) => (b[0].freq || 0) - (a[0].freq || 0) || a[1] - b[1]) // desc, stable on ties
        .map((p) => p[0]);
    }
    return list;
  }, [scope, sortMode]);

  const newAllowance = (settings.newPerDay || 0) + (daily.extraNew || 0) - (daily.newDone || 0);

  function pickNext(cards, sc, dl, nowMs) {
    let learn = null;
    let review = null;
    for (const c of cards) {
      const s = sc[c.id];
      if (!s) continue;
      if ((s.state === "learning" || s.state === "relearning") && s.due <= nowMs) {
        if (!learn || s.due < sc[learn].due) learn = c.id;
      } else if (s.state === "review" && s.due <= nowMs) {
        if (!review || s.due < sc[review].due) review = c.id;
      }
    }
    if (learn) return { id: learn, isNew: false };
    if (review) return { id: review, isNew: false };
    const allow = (settings.newPerDay || 0) + (dl.extraNew || 0) - (dl.newDone || 0);
    if (allow > 0) {
      for (const c of cards) if (!sc[c.id]) return { id: c.id, isNew: true };
    }
    return null;
  }
  // Revision picker: same real-time SRS as study, but over revSched and with NO daily new-card cap
  // (revision is a self-paced cram of the whole merged set). Returns the earliest due learning/review
  // card, else the next unseen card, else null (everything left is scheduled in the future).
  function pickNextRev(cards, sc, nowMs) {
    let learn = null;
    let review = null;
    let fresh = null;
    for (const c of cards) {
      const s = sc[c.id];
      if (!s) {
        if (!fresh) fresh = c.id;
        continue;
      }
      if ((s.state === "learning" || s.state === "relearning") && s.due <= nowMs) {
        if (!learn || s.due < sc[learn].due) learn = c.id;
      } else if (s.state === "review" && s.due <= nowMs) {
        if (!review || s.due < sc[review].due) review = c.id;
      }
    }
    if (learn) return { id: learn, isNew: false };
    if (review) return { id: review, isNew: false };
    if (fresh) return { id: fresh, isNew: true };
    return null;
  }
  const dirFor = () => {
    const m = settings.direction;
    return m === "mix" ? (Math.random() < 0.5 ? "jp" : "en") : m;
  };

  /* ---- auto-advance when no current card (SRS study only; revision is linear) ---- */
  useEffect(() => {
    if (!ready || view !== "study" || cur || scope.type === "merged") return;
    const n = pickNext(scopeCards, sched, daily, now);
    if (n) {
      n.dir = dirFor();
      setCur(n);
      setRevealed(false);
    }
    // eslint-disable-next-line
  }, [now, cur, ready, view, scopeCards, sched, daily, settings.newPerDay]);

  /* ---- revision: drive the current card ---- */
  useEffect(() => {
    if (view !== "study" || scope.type !== "merged") return;
    if (revMode === "srs") {
      // real-time SRS: pick the next due/new card from revSched. When nothing is due, leave cur empty
      // (done screen) and re-pick automatically as the clock ticks and a card's timer comes due.
      if (cur) return;
      const n = pickNextRev(scopeCards, revSched, now);
      if (n) {
        n.dir = settings.direction === "en" ? "en" : "jp";
        setCur(n);
        setRevealed(false);
      }
      return;
    }
    // flip mode ("Got it / Again"): linear walk through the captured queue
    const id = revQueue[revPos];
    if (id && (!cur || cur.id !== id)) {
      setCur({ id, isNew: !revSched[id], dir: settings.direction === "en" ? "en" : "jp" });
    } else if (!id && cur) {
      setCur(null); // reached the end → done screen
    }
    // eslint-disable-next-line
  }, [view, scope, revPos, revQueue, revMode, now, cur, revSched, scopeCards]);

  function startStudy(sc) {
    setScope(sc);
    setCur(null);
    setRevealed(false);
    setView("study"); // keep the undo stack — undo can step back into earlier cards across navigation
  }

  /* ---- revision (merged sections, linear flip-through) ---- */
  // most-frequent-first ordering of a list of card ids (stable; ties keep the given order)
  function freqOrderIds(ids) {
    return ids
      .map((id, i) => [id, i])
      .sort((a, b) => ((CARD_BY_ID[b[0]].freq || 0) - (CARD_BY_ID[a[0]].freq || 0)) || a[1] - b[1])
      .map((p) => p[0]);
  }
  function startRevision(mg, unknownOnly) {
    const base = mg === -1 ? MERGED.flatMap((g) => g.ids) : MERGED[mg].ids;
    let q = unknownOnly ? base.filter((id) => !revKnown[id]) : base;
    if (!q.length) q = base; // nothing unknown left → review everything
    if (sortMode === "freq") q = freqOrderIds(q); // most common first
    setScope({ type: "merged", mg });
    setRevQueue(q);
    setRevPos(0);
    setCur(null);
    setRevealed(false);
    setView("study"); // keep the undo stack — undo can step back into earlier cards across navigation
  }
  // toggling the sort mode should take effect immediately on screen, not only on the next card
  function changeSort(mode) {
    if (mode === sortMode) return;
    setSortMode(mode);
    if (view !== "study") return;
    if (scope.type === "merged" && revMode === "flip") {
      // reorder the not-yet-seen tail of the flip queue (keep what you've already passed)
      const base = scope.mg === -1 ? MERGED.flatMap((g) => g.ids) : MERGED[scope.mg].ids;
      const ord = new Map(base.map((id, i) => [id, i]));
      setRevQueue((qq) => {
        const passed = qq.slice(0, revPos);
        let rest = qq.slice(revPos);
        rest = mode === "freq" ? freqOrderIds(rest) : rest.slice().sort((a, b) => (ord.get(a) ?? 0) - (ord.get(b) ?? 0));
        return [...passed, ...rest];
      });
      setCur(null); // flip effect re-reads revQueue[revPos] = first of the reordered tail
      setRevealed(false);
    } else if (cur && cur.isNew) {
      // study / revision-SRS: jump to the first card of the new order (only swaps a fresh, ungraded new card)
      setCur(null);
      setRevealed(false);
    }
  }
  function revAdvance(markKnown) {
    if (cur) {
      const id = cur.id;
      // "Again" (not known) re-queues the card so it returns a few cards later in this same pass
      const requeuedAt = !markKnown ? Math.min(revPos + 3, revQueue.length) : -1;
      if (requeuedAt >= 0) setRevQueue((q) => { const nq = q.slice(); nq.splice(Math.min(revPos + 3, nq.length), 0, id); return nq; });
      setUndoStack((u) => [...u, { id, dir: cur.dir, isNew: cur.isNew, schedChanged: false, dailyChanged: false, rev: true, pos: revPos, prevKnown: !!revKnown[id], requeuedAt, scope, revMode }].slice(-60));
      setRevKnown((k) => {
        const n = { ...k };
        if (markKnown) n[id] = true;
        else delete n[id];
        return n;
      });
    }
    setRevealed(false);
    setRevPos((p) => p + 1);
  }

  /* ---- keyboard shortcuts (desktop/web): space reveal · 1-4 grade · z undo · esc back ---- */
  useEffect(() => {
    if (view !== "study") return;
    const onKey = (e) => {
      if (showSettings || editing != null) return;
      const tag = (e.target && e.target.tagName) || "";
      if (tag === "INPUT" || tag === "TEXTAREA" || e.metaKey || e.ctrlKey || e.altKey) return;
      const k = e.key;
      if (k === "Escape") { setView("home"); return; }
      if ((k === "z" || k === "Z" || k === "u" || k === "U") && undoStack.length) { e.preventDefault(); doUndo(); return; }
      if (!cur) return;
      if (!revealed) {
        if (k === " " || k === "Enter") { e.preventDefault(); doReveal(); }
        return;
      }
      if (scope.type === "merged") {
        if (revMode === "srs") {
          if (k >= "1" && k <= "4") { e.preventDefault(); doGrade(parseInt(k, 10) - 1); return; } // 1-4 = grade
          if (k === " " || k === "Enter") { e.preventDefault(); doGrade(2); return; } // space = Good
          return;
        }
        if (k === " " || k === "Enter") { e.preventDefault(); revAdvance(true); return; } // space = Got it
        if (k === "x" || k === "X") { e.preventDefault(); revAdvance(false); return; } // x = Again
        return;
      }
      if (k === " " || k === "Enter") { e.preventDefault(); doGrade(2); return; } // space = Good once revealed
      if (k >= "1" && k <= "4") { e.preventDefault(); doGrade(parseInt(k, 10) - 1); }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
    // eslint-disable-next-line
  }, [view, showSettings, editing, cur, revealed, undoStack.length, sched, revSched, scopeCards, daily, settings.direction, scope, revMode]);

  function doGrade(g) {
    if (!cur || !revealed) return;
    haptic(g === 0 ? [8, 30, 8] : 10);
    const id = cur.id;

    if (scope.type === "merged") {
      // revision = real-time SRS on its OWN schedule (revSched), exactly like By-level study:
      // Again comes back in ~1 min, Good after the learning steps, Easy graduates out. No fixed-position
      // re-queue — the card returns when its timer actually comes due.
      const prevR = revSched[id] ? { ...revSched[id] } : null;
      const nsR = applyGrade(prevR, g, Date.now());
      const nRevSched = { ...revSched, [id]: nsR };
      setRevSched(nRevSched);
      setRevKnown((k) => {
        const n = { ...k };
        if (g > 0) n[id] = true; // Again leaves it "unknown", else "got it"
        else delete n[id];
        return n;
      });
      setUndoStack((u) => [...u, { id, dir: cur.dir, isNew: cur.isNew, rev: true, revSchedChanged: true, prevRevSched: prevR, prevKnown: !!revKnown[id], scope, revMode }].slice(-60));
      const n = pickNextRev(scopeCards, nRevSched, Date.now());
      if (n) n.dir = settings.direction === "en" ? "en" : "jp";
      setCur(n);
      setRevealed(false);
      setActiveGrade(-1);
      return;
    }

    // By-level / per-section study
    const prev = sched[id] ? { ...sched[id] } : null;
    const ns = applyGrade(prev, g, Date.now());
    const nSched = { ...sched, [id]: ns };
    setSched(nSched);
    const nDaily = {
      ...daily,
      reviewsToday: (daily.reviewsToday || 0) + 1,
      newDone: daily.newDone + (cur.isNew ? 1 : 0),
    };
    setUndoStack((u) => [...u, { id, dir: cur.dir, isNew: cur.isNew, schedChanged: true, prevSched: prev, dailyChanged: true, prevDaily: { ...daily }, rev: false, scope }].slice(-60));
    setDaily(nDaily);
    const n = pickNext(scopeCards, nSched, nDaily, Date.now());
    if (n) n.dir = dirFor();
    setCur(n);
    setRevealed(false);
    setActiveGrade(-1);
  }

  function doReveal() {
    if (revealed) return;
    haptic(6);
    setRevealed(true);
  }

  function doUndo() {
    if (!undoStack.length) return;
    haptic(6);
    const snap = undoStack[undoStack.length - 1];
    // bring back the screen this card belonged to (so undo works after navigating away and back)
    if (snap.scope) setScope(snap.scope);
    if (snap.rev && snap.revMode) setRevMode(snap.revMode);
    if (snap.schedChanged)
      setSched((s) => {
        const c = { ...s };
        if (snap.prevSched) c[snap.id] = snap.prevSched;
        else delete c[snap.id];
        return c;
      });
    if (snap.dailyChanged && snap.prevDaily) setDaily(snap.prevDaily);
    if (snap.revSchedChanged)
      setRevSched((s) => {
        const c = { ...s };
        if (snap.prevRevSched) c[snap.id] = snap.prevRevSched;
        else delete c[snap.id];
        return c;
      });
    if (snap.rev) {
      // flip-mode undo (has a queue position): undo any "Again" re-queue and step the pointer back
      if (snap.requeuedAt != null && snap.requeuedAt >= 0)
        setRevQueue((q) => { const nq = q.slice(); if (nq[snap.requeuedAt] === snap.id) nq.splice(snap.requeuedAt, 1); return nq; });
      if (snap.pos != null) setRevPos(snap.pos);
      setRevKnown((k) => {
        const n = { ...k };
        if (snap.prevKnown) n[snap.id] = true;
        else delete n[snap.id];
        return n;
      });
    }
    setCur({ id: snap.id, isNew: snap.isNew, dir: snap.dir });
    setRevealed(true);
    setUndoStack((u) => u.slice(0, -1));
  }

  function fireToast(msg) {
    setToast({ msg, id: Date.now() });
    if (toastTimer.current) clearTimeout(toastTimer.current);
    toastTimer.current = setTimeout(() => setToast(null), 1150);
  }
  function copyField(field, text) {
    if (!text) return;
    copyText(text);
    fireToast("Copied " + text);
    setFlash(field);
    setTimeout(() => setFlash((f) => (f === field ? null : f)), 320);
  }
  /* ---- one-tap paste: clipboard fully replaces this card's breakdown, saved + synced automatically ---- */
  async function pasteToCard(id) {
    const text = await readClipboard();
    if (text == null) {
      // browser refused clipboard access — fall back to the editor so the user can paste manually
      setEditing(id);
      fireToast("Paste into the editor");
      return;
    }
    if (!text.trim()) {
      fireToast("Clipboard is empty");
      return;
    }
    setBdEdits((m) => ({ ...m, [id]: text })); // auto-saved by the persist effect + pushed by cloud sync
    fireToast("Card replaced from clipboard");
  }

  /* ---- counters for study header ---- */
  // data-only snapshot for cross-device transfer (no navigation fields)
  const exportBlob = { v: 1, deckRev: DECK_REV, sched, daily, settings, theme, homeMode, revMode, sortMode, revKnown, revSched, bdEdits };
  const exportJson = JSON.stringify(exportBlob);

  /* ---- cloud sync: pull on open / focus / interval, push (debounced) on change ---- */
  useEffect(() => {
    if (!ready || !syncOn) return;
    pullCloud();
    const onVis = () => { if (typeof document === "undefined" || !document.hidden) pullCloud(); };
    if (typeof document !== "undefined") document.addEventListener("visibilitychange", onVis);
    if (typeof window !== "undefined") window.addEventListener("focus", onVis);
    const iv = setInterval(onVis, 45000);
    return () => {
      if (typeof document !== "undefined") document.removeEventListener("visibilitychange", onVis);
      if (typeof window !== "undefined") window.removeEventListener("focus", onVis);
      clearInterval(iv);
    };
    // eslint-disable-next-line
  }, [ready, syncOn]);

  useEffect(() => {
    if (!ready || !syncOn || !initialPullDoneRef.current) return; // wait for the first pull so we don't clobber newer cloud data
    if (exportJson === lastPushedJsonRef.current) return; // unchanged / echo of what we just synced
    const t = setTimeout(() => {
      const ts = Date.now();
      setSyncTs(ts);
      syncTsRef.current = ts;
      pushCloud(exportBlob, ts, exportJson);
    }, 1200);
    return () => clearTimeout(t);
    // eslint-disable-next-line
  }, [exportJson, ready, syncOn]);

  const counters = useMemo(() => {
    let learn = 0;
    let due = 0;
    let newLeft = 0;
    for (const c of scopeCards) {
      const s = sched[c.id];
      if (!s) {
        newLeft++;
        continue;
      }
      if ((s.state === "learning" || s.state === "relearning") && s.due <= now) learn++;
      else if (s.state === "review" && s.due <= now) due++;
    }
    const newShow = Math.max(0, Math.min(newLeft, newAllowance));
    return { learn, due, newShow, newLeft };
  }, [scopeCards, sched, now, newAllowance]);

  /* ---- today's overall progress (scope-independent momentum bar) ---- */
  const dayProgress = useMemo(() => {
    let queue = 0;
    let newGlobal = 0;
    for (const c of CARDS) {
      const s = sched[c.id];
      if (!s) { newGlobal++; continue; }
      if (s.due <= now && (s.state === "review" || s.state === "learning" || s.state === "relearning")) queue++;
    }
    queue += Math.max(0, Math.min(newGlobal, newAllowance));
    const done = daily.reviewsToday || 0;
    const total = done + queue;
    return { done, remaining: queue, pct: total ? done / total : 0 };
  }, [sched, now, newAllowance, daily.reviewsToday]);

  /* ---- next due (for done screen) ---- */
  const nextDue = useMemo(() => {
    let nd = Infinity;
    for (const c of scopeCards) {
      const s = sched[c.id];
      if (s && s.due > now) nd = Math.min(nd, s.due);
    }
    return nd;
  }, [scopeCards, sched, now]);

  /* ---- collection-wide progress stats ---- */
  const stats = useMemo(() => {
    let seen = 0;
    let relearning = 0;
    let maturing = 0;
    let mature = 0;
    for (const id in sched) {
      const s = sched[id];
      seen++;
      if (s.state === "relearning") relearning++;
      if (s.state === "review") {
        if (s.interval >= 21) mature++;
        else maturing++;
      }
    }
    return { seen, relearning, maturing, mature, total: CARDS.length };
  }, [sched]);

  /* ---- home: per-section progress ---- */
  const homeStats = useMemo(() => {
    return DECK.map((s, si) => {
      let total = 0;
      let seen = 0;
      let due = 0;
      let newLeft = 0;
      let mature = 0;
      for (const c of CARDS) {
        if (c.si !== si) continue;
        total++;
        const sc = sched[c.id];
        if (!sc) {
          newLeft++;
          continue;
        }
        seen++;
        if (sc.state === "review" && sc.interval >= 21) mature++;
        if (sc.due <= now && (sc.state === "review" || sc.state === "learning" || sc.state === "relearning")) due++;
      }
      return { total, seen, due, newLeft, mature };
    });
  }, [sched, now]);

  /* ---- revision: per-merged-group "got it" progress ---- */
  const revStats = useMemo(
    () => MERGED.map((g) => ({ total: g.ids.length, known: g.ids.reduce((a, id) => a + (revKnown[id] ? 1 : 0), 0) })),
    [revKnown]
  );
  const revTotalKnown = revStats.reduce((a, s) => a + s.known, 0);
  const revTotalCards = MERGED.reduce((a, g) => a + g.ids.length, 0);

  /* ---- live stats for the revision set currently being studied (SRS mode) ---- */
  const revSet = useMemo(() => {
    if (scope.type !== "merged") return { total: 0, known: 0, dueNow: 0, nextDue: Infinity };
    const ids = scope.mg === -1 ? MERGED.flatMap((g) => g.ids) : MERGED[scope.mg].ids;
    let known = 0;
    let dueNow = 0;
    let nextDue = Infinity;
    for (const id of ids) {
      if (revKnown[id]) known++;
      const s = revSched[id];
      if (!s || s.due <= now) dueNow++; // unseen or due right now
      else if (s.due > now) nextDue = Math.min(nextDue, s.due);
    }
    return { total: ids.length, known, dueNow, nextDue };
  }, [scope, revKnown, revSched, now]);

  if (!ready) {
    return (
      <Shell>
        <div style={{ flex: 1, display: "grid", placeItems: "center", color: C.faint, fontFamily: FJP }}>
          読み込み中…
        </div>
      </Shell>
    );
  }

  /* ================================ HOME ================================== */
  if (view === "home") {
    const totalDue = homeStats.reduce((a, s) => a + s.due, 0);
    const totalNew = Math.max(0, Math.min(homeStats.reduce((a, s) => a + s.newLeft, 0), newAllowance));
    return (
      <Shell>
        <Style />
        <header style={hdr}>
          <div style={{ display: "flex", alignItems: "baseline", gap: 9 }}>
            <span style={{ fontFamily: FDISP, fontWeight: 900, fontSize: 21, color: C.ink, letterSpacing: 0.3 }}>
              {LEVELS.join(" · ")}
            </span>
            <span style={{ fontFamily: FJP, fontSize: 12.5, color: C.sub, letterSpacing: 2 }}>語彙 · SRS</span>
          </div>
          <IconBtn onClick={() => setShowSettings(true)} label="⚙" />
        </header>

        <div className="n5-scroll" style={{ flex: 1, minHeight: 0, overflowY: "auto", padding: "8px 14px 18px" }}>
          <div style={modeToggle}>
            {[["level", "By Level"], ["revision", "Revision"]].map(([m, lab]) => (
              <button key={m} onClick={() => setHomeMode(m)} className="n5press" style={modeTab(homeMode === m)}>
                {lab}
              </button>
            ))}
          </div>

          {homeMode === "level" && (<>
          <div className="n5stagger" style={heroCard}>
            <div style={{ display: "flex", alignItems: "center", gap: 15 }}>
              <Ring
                pct={dayProgress.pct}
                size={66}
                stroke={6}
                color={dayProgress.done + dayProgress.remaining === 0 ? C.faint : dayProgress.remaining === 0 ? C.good : C.gold}
              >
                <span style={{ fontFamily: FDISP, fontWeight: 900, fontSize: 16, color: C.ink, lineHeight: 1, fontVariantNumeric: "tabular-nums" }}>
                  {Math.round(dayProgress.pct * 100)}
                  <span style={{ fontSize: 8.5, color: C.sub, fontWeight: 700 }}>%</span>
                </span>
              </Ring>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontFamily: FJP, fontSize: 10.5, letterSpacing: 2.5, color: C.faint }}>TODAY</div>
                <div style={{ display: "flex", alignItems: "baseline", gap: 6, marginTop: 4 }}>
                  <span style={{ fontFamily: FDISP, fontWeight: 900, fontSize: 27, color: C.ink, lineHeight: 1, fontVariantNumeric: "tabular-nums" }}>
                    {daily.reviewsToday || 0}
                  </span>
                  <span style={{ fontFamily: FJP, fontSize: 12.5, color: C.sub }}>reviewed</span>
                </div>
                <div style={{ fontFamily: FJP, fontSize: 12, color: dayProgress.remaining > 0 ? C.sub : C.good, marginTop: 4 }}>
                  {dayProgress.remaining > 0
                    ? dayProgress.remaining + " left in today's queue"
                    : dayProgress.done > 0
                    ? "All caught up — nicely done"
                    : "Nothing due right now"}
                </div>
              </div>
            </div>
            <div style={{ height: 1, background: C.line, margin: "14px 0 12px" }} />
            <div style={{ display: "flex", alignItems: "center", gap: 14, fontFamily: FJP, fontSize: 11.5 }}>
              <span style={legend}><i style={dotS(C.good)} />{stats.mature} mastered</span>
              <span style={legend}><i style={dotS(hexA(C.easy, 0.85))} />{Math.max(0, stats.seen - stats.mature)} learning</span>
              <span style={{ marginLeft: "auto", color: C.faint, fontVariantNumeric: "tabular-nums" }}>{stats.seen}/{stats.total}</span>
            </div>
            <div style={{ marginTop: 10, height: 7, background: "var(--track)", borderRadius: 7, overflow: "hidden", display: "flex" }}>
              <div style={{ width: (stats.total ? (stats.mature / stats.total) * 100 : 0) + "%", height: "100%", background: C.good, transition: "width .5s ease" }} />
              <div style={{ width: (stats.total ? (Math.max(0, stats.seen - stats.mature) / stats.total) * 100 : 0) + "%", height: "100%", background: hexA(C.easy, 0.7), transition: "width .5s ease" }} />
            </div>
          </div>
          <button onClick={() => startStudy({ type: "all" })} className="n5press n5lift n5stagger" style={{ ...allCardBtn, animationDelay: ".05s" }}>
            <div>
              <div style={{ fontFamily: FDISP, fontWeight: 800, fontSize: 18, color: INK_GOLD }}>Study everything</div>
              <div style={{ fontSize: 12.5, color: "rgba(42,28,6,0.68)", marginTop: 3, fontFamily: FJP }}>
                All {CARDS.length} words · {SECTIONS.length} sections
              </div>
            </div>
            <div style={{ display: "flex", gap: 6 }}>
              <MiniPill n={totalNew} c={INK_GOLD} bg="rgba(42,28,6,0.13)" t="new" dark />
              <MiniPill n={totalDue} c={INK_GOLD} bg="rgba(42,28,6,0.13)" t="due" dark />
            </div>
          </button>

          {LEVELS.map((lv) => {
            const idxs = DECK.map((_, i) => i).filter((i) => (DECK[i].level || "N5") === lv);
            const lvWords = CARDS.filter((c) => c.level === lv).length;
            return (
              <div key={lv}>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", margin: "22px 4px 11px" }}>
                  <div style={{ display: "flex", alignItems: "baseline", gap: 9 }}>
                    <span style={{ fontFamily: FDISP, fontWeight: 900, fontSize: 13, color: C.ink, letterSpacing: 1 }}>{lv}</span>
                    <span style={{ fontSize: 10.5, letterSpacing: 2, color: C.faint, fontFamily: FJP }}>{lvWords} WORDS</span>
                  </div>
                  <button onClick={() => startStudy({ type: "level", level: lv })} className="n5press" style={studyAllPill}>
                    Study all {lv}
                  </button>
                </div>
                {idxs.map((si) => {
                  const s = DECK[si];
                  const hs = homeStats[si];
                  const pct = Math.round((hs.seen / hs.total) * 100);
                  const newShow = Math.max(0, Math.min(hs.newLeft, newAllowance));
                  const mastered = hs.total > 0 && hs.mature === hs.total;
                  const restful = !mastered && newShow === 0 && hs.due === 0 && hs.seen > 0;
                  return (
                    <button key={si} onClick={() => startStudy({ type: "section", si })} className="n5press n5lift" style={secBtn}>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div
                          style={{
                            fontFamily: FJP,
                            fontWeight: 700,
                            fontSize: 15,
                            color: C.ink,
                            whiteSpace: "nowrap",
                            overflow: "hidden",
                            textOverflow: "ellipsis",
                          }}
                        >
                          {s.name}
                        </div>
                        <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 7 }}>
                          <div style={{ flex: 1, height: 5, background: C.bg2, borderRadius: 5, overflow: "hidden" }}>
                            <div
                              style={{
                                width: pct + "%",
                                height: "100%",
                                background: mastered ? C.gold : `linear-gradient(90deg, ${hexA(C.seal, 0.85)}, ${C.seal})`,
                                borderRadius: 5,
                                transition: "width .45s ease",
                              }}
                            />
                          </div>
                          <span style={{ fontSize: 11, color: C.faint, fontVariantNumeric: "tabular-nums" }}>
                            {hs.seen}/{hs.total}
                          </span>
                        </div>
                      </div>
                      <div style={{ display: "flex", gap: 6, marginLeft: 12, alignItems: "center" }}>
                        {mastered ? (
                          <span style={doneBadge(C.gold)} title="Mastered">★</span>
                        ) : restful ? (
                          <span style={doneBadge(C.good)} title="Caught up">✓</span>
                        ) : (
                          <>
                            <MiniPill n={newShow} c={C.gold} bg={hexA(C.gold, 0.12)} t="new" />
                            <MiniPill n={hs.due} c={C.easy} bg={hexA(C.easy, 0.12)} t="due" />
                          </>
                        )}
                      </div>
                    </button>
                  );
                })}
              </div>
            );
          })}
          </>)}

          {homeMode === "revision" && (<>
            <div className="n5stagger" style={heroCard}>
              <div style={{ display: "flex", alignItems: "center", gap: 15 }}>
                <Ring
                  pct={revTotalCards ? revTotalKnown / revTotalCards : 0}
                  size={66}
                  stroke={6}
                  color={revTotalCards && revTotalKnown >= revTotalCards ? C.good : C.seal}
                >
                  <span style={{ fontFamily: FDISP, fontWeight: 900, fontSize: 16, color: C.ink, lineHeight: 1, fontVariantNumeric: "tabular-nums" }}>
                    {Math.round((revTotalCards ? revTotalKnown / revTotalCards : 0) * 100)}
                    <span style={{ fontSize: 8.5, color: C.sub, fontWeight: 700 }}>%</span>
                  </span>
                </Ring>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontFamily: FJP, fontSize: 10.5, letterSpacing: 2.5, color: C.faint }}>REVISION · N5+N4+N3</div>
                  <div style={{ display: "flex", alignItems: "baseline", gap: 6, marginTop: 4 }}>
                    <span style={{ fontFamily: FDISP, fontWeight: 900, fontSize: 27, color: C.ink, lineHeight: 1, fontVariantNumeric: "tabular-nums" }}>{revTotalKnown}</span>
                    <span style={{ fontFamily: FJP, fontSize: 12.5, color: C.sub }}>/ {revTotalCards} got it</span>
                  </div>
                  <div style={{ fontFamily: FJP, fontSize: 12, color: C.sub, marginTop: 4 }}>Merged by type → theme · easiest first</div>
                </div>
              </div>
            </div>
            <button onClick={() => startRevision(-1, false)} className="n5press n5lift n5stagger" style={{ ...allCardBtn, animationDelay: ".05s" }}>
              <div>
                <div style={{ fontFamily: FDISP, fontWeight: 800, fontSize: 18, color: INK_GOLD }}>Revise everything</div>
                <div style={{ fontSize: 12.5, color: "rgba(42,28,6,0.68)", marginTop: 3, fontFamily: FJP }}>
                  All {revTotalCards} words · {MERGED.length} merged sets
                </div>
              </div>
              <span style={{ fontFamily: FDISP, fontWeight: 900, fontSize: 22, color: INK_GOLD }}>→</span>
            </button>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", margin: "20px 4px 11px" }}>
              <span style={{ fontSize: 10.5, letterSpacing: 2, color: C.faint, fontFamily: FJP }}>MERGED SECTIONS · {MERGED.length}</span>
              {revTotalKnown > 0 &&
                (confirmRevReset ? (
                  <span style={{ display: "flex", gap: 6 }}>
                    <button
                      onClick={() => { setRevKnown({}); setConfirmRevReset(false); fireToast("Revision progress reset"); }}
                      className="n5press"
                      style={{ ...studyAllPill, background: hexA(C.again, 0.14), border: "1px solid " + hexA(C.again, 0.5), color: C.again }}
                    >
                      Reset
                    </button>
                    <button onClick={() => setConfirmRevReset(false)} className="n5press" style={studyAllPill}>Cancel</button>
                  </span>
                ) : (
                  <button onClick={() => setConfirmRevReset(true)} className="n5press" style={studyAllPill}>Reset progress</button>
                ))}
            </div>
            {MERGED.map((g, gi) => {
              const rs = revStats[gi];
              const pct = rs.total ? Math.round((rs.known / rs.total) * 100) : 0;
              const done = rs.total > 0 && rs.known === rs.total;
              return (
                <button key={gi} onClick={() => startRevision(gi, rs.known > 0 && !done)} className="n5press n5lift" style={secBtn}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontFamily: FJP, fontWeight: 700, fontSize: 15, color: C.ink, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                      {g.name}
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 7 }}>
                      <div style={{ flex: 1, height: 5, background: C.bg2, borderRadius: 5, overflow: "hidden" }}>
                        <div style={{ width: pct + "%", height: "100%", background: done ? C.good : `linear-gradient(90deg, ${hexA(C.seal, 0.85)}, ${C.seal})`, borderRadius: 5, transition: "width .45s ease" }} />
                      </div>
                      <span style={{ fontSize: 11, color: C.faint, fontVariantNumeric: "tabular-nums" }}>{rs.known}/{rs.total}</span>
                    </div>
                    <div style={{ display: "flex", gap: 5, marginTop: 6 }}>
                      {["N5", "N4", "N3"].map((lv) => (g.levels[lv] ? <span key={lv} style={lvChip(lv)}>{lv} · {g.levels[lv]}</span> : null))}
                    </div>
                  </div>
                  <div style={{ marginLeft: 12, flex: "0 0 auto" }}>
                    {done ? <span style={doneBadge(C.good)} title="All got it">✓</span> : <span style={{ fontFamily: FDISP, fontWeight: 900, fontSize: 18, color: C.seal }}>→</span>}
                  </div>
                </button>
              );
            })}
          </>)}
          <div style={{ height: 6 }} />
        </div>

        {showSettings && (
          <SettingsSheet
            settings={settings}
            setSettings={setSettings}
            theme={theme}
            setTheme={setTheme}
            stats={stats}
            daily={daily}
            confirmReset={confirmReset}
            setConfirmReset={setConfirmReset}
            onReset={(target) => {
              if (target === "level" || target === "all") {
                setSched({});
                setDaily({ date: todayStr(Date.now()), newDone: 0, reviewsToday: 0, extraNew: 0 });
              }
              if (target === "revision" || target === "all") {
                setRevSched({});
                setRevKnown({});
                setRevQueue([]);
                setRevPos(0);
              }
              setUndoStack([]);
              setConfirmReset(false);
              setShowSettings(false);
            }}
            onClose={() => {
              setShowSettings(false);
              setConfirmReset(false);
            }}
            bdEdits={bdEdits}
            setBdEdits={setBdEdits}
            exportBlob={exportBlob}
            onImportData={applyData}
            syncOn={syncOn}
            setSyncOn={setSyncOn}
            syncState={syncState}
          />
        )}
      </Shell>
    );
  }

  /* ================================ STUDY ================================= */
  const card = cur ? CARD_BY_ID[cur.id] : null;
  const dir = cur ? cur.dir : "jp";
  const hasKanji = card && card.kanji && card.kanji !== card.kana;
  const promptWord = card ? (dir === "en" ? card.meaning || card.kana : hasKanji ? card.kanji : card.kana) : "";

  /* SRS grade bar (Again/Hard/Good/Easy) — used in normal study and the revision SRS grade */
  const gradeSched = scope.type === "merged" ? revSched : sched; // revision grades its own schedule
  const srsGradeBar = cur ? (
    <div style={gradeBar}>
      {[
        { g: 0, label: "Again", color: C.again },
        { g: 1, label: "Hard", color: C.hard },
        { g: 2, label: "Good", color: C.good },
        { g: 3, label: "Easy", color: C.easy },
      ].map((b, i) => {
        const span = fmtSpan(applyGrade(gradeSched[cur.id] || null, b.g, now).due - now);
        return (
          <button
            key={b.g}
            className="n5press"
            onClick={() => doGrade(b.g)}
            onPointerDown={() => setActiveGrade(b.g)}
            onPointerUp={() => setActiveGrade(-1)}
            onPointerLeave={() => setActiveGrade((a) => (a === b.g ? -1 : a))}
            style={{
              flex: 1,
              height: "100%",
              borderTop: "none",
              borderRight: "none",
              borderBottom: "none",
              borderLeft: i === 0 ? "none" : "1px solid " + C.line,
              background: activeGrade === b.g ? hexA(b.color, 0.18) : "transparent",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
              gap: 3,
              cursor: "pointer",
              position: "relative",
              transition: "background .08s",
            }}
          >
            <span className="n5-kbd-hint" style={{ position: "absolute", top: 6, fontSize: 9, color: hexA(b.color, 0.55), fontFamily: FJP, fontWeight: 700 }}>
              {b.g + 1}
            </span>
            <span style={{ fontSize: 11.5, color: hexA(b.color, 0.85), fontVariantNumeric: "tabular-nums", fontFamily: FJP }}>{span}</span>
            <span style={{ fontSize: 16, fontWeight: 700, color: b.color, fontFamily: FDISP, letterSpacing: 0.2 }}>{b.label}</span>
          </button>
        );
      })}
    </div>
  ) : null;

  return (
    <Shell>
      <Style />
      <header style={hdr}>
        <IconBtn onClick={() => setView("home")} label="‹" />
        <div style={{ flex: 1, textAlign: "center", minWidth: 0, padding: "0 6px" }}>
          <div
            style={{
              fontFamily: FJP,
              fontSize: 13.5,
              fontWeight: 700,
              color: C.ink,
              whiteSpace: "nowrap",
              overflow: "hidden",
              textOverflow: "ellipsis",
            }}
          >
            {scope.type === "all"
              ? "All sections"
              : scope.type === "level"
              ? scope.level + " · all sections"
              : scope.type === "merged"
              ? scope.mg === -1 ? "Revise everything" : MERGED[scope.mg].name
              : SECTIONS[scope.si]}
          </div>
        </div>
        <IconBtn onClick={doUndo} label="↶" disabled={!undoStack.length} />
        {scope.type === "merged" && (
          <div style={revModeTog} title="Answer mode">
            {[["flip", "Got it"], ["srs", "SRS"]].map(([m, lbl]) => (
              <button key={m} onClick={() => setRevMode(m)} className="n5press" style={revModeSeg(revMode === m)}>
                {lbl}
              </button>
            ))}
          </div>
        )}
        <div style={revModeTog} title="Card order — Freq shows the most common words first">
          {[["section", "Order"], ["freq", "Freq"]].map(([m, lbl]) => (
            <button key={m} onClick={() => changeSort(m)} className="n5press" style={revModeSeg(sortMode === m)}>
              {lbl}
            </button>
          ))}
        </div>
        <IconBtn onClick={() => setShowSettings(true)} label="⚙" />
      </header>

      {scope.type === "merged" ? (
        <div style={{ padding: "9px 18px 4px", flex: "0 0 auto" }}>
          <div style={{ height: 6, background: "var(--track)", borderRadius: 6, overflow: "hidden" }}>
            <div
              style={{
                width:
                  (revMode === "srs"
                    ? revSet.total ? (revSet.known / revSet.total) * 100 : 0
                    : revQueue.length ? (revPos / revQueue.length) * 100 : 0) + "%",
                height: "100%",
                borderRadius: 6,
                background: `linear-gradient(90deg, ${hexA(C.seal, 0.85)}, ${C.seal})`,
                transition: "width .3s ease",
              }}
            />
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
            <span style={{ fontSize: 9.5, letterSpacing: 1, color: C.faint, fontFamily: FJP }}>REVISION</span>
            <span style={{ fontSize: 9.5, color: C.faint, fontFamily: FJP, fontVariantNumeric: "tabular-nums" }}>
              {revMode === "srs"
                ? `${revSet.known} / ${revSet.total} learned${revSet.dueNow ? " · " + revSet.dueNow + " due" : ""}`
                : `${Math.min(revPos + 1, revQueue.length)} / ${revQueue.length}`}
            </span>
          </div>
        </div>
      ) : (
        <>
          <div style={ctr}>
            <Counter label="NEW" n={counters.newShow} color={C.gold} />
            <Counter label="LRN" n={counters.learn} color={C.learn} />
            <Counter label="DUE" n={counters.due} color={C.easy} />
          </div>
          {(dayProgress.done > 0 || dayProgress.remaining > 0) && (
            <div style={{ padding: "0 18px 2px", flex: "0 0 auto" }}>
              <div style={{ height: 5, background: "var(--track)", borderRadius: 5, overflow: "hidden" }}>
                <div
                  style={{
                    width: Math.round(dayProgress.pct * 100) + "%",
                    height: "100%",
                    borderRadius: 5,
                    background: `linear-gradient(90deg, ${C.gold}, ${C.good})`,
                    transition: "width .35s ease",
                  }}
                />
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
                <span style={{ fontSize: 9.5, letterSpacing: 1, color: C.faint, fontFamily: FJP }}>TODAY</span>
                <span style={{ fontSize: 9.5, color: C.faint, fontFamily: FJP, fontVariantNumeric: "tabular-nums" }}>
                  {dayProgress.done} done · {dayProgress.remaining} left
                </span>
              </div>
            </div>
          )}
        </>
      )}

      {card ? (
        <>
          <div
            className="n5-scroll"
            onClick={doReveal}
            style={{
              flex: 1,
              minHeight: 0,
              overflowY: "auto",
              margin: "10px 14px 0",
              borderRadius: 20,
              background: `linear-gradient(180deg, ${C.bg1}, ${C.bg2})`,
              border: "1px solid " + C.line,
              boxShadow: "0 14px 40px rgba(0,0,0,0.34)",
              cursor: revealed ? "default" : "pointer",
              position: "relative",
            }}
          >
            <div style={{ padding: "22px 20px 26px", minHeight: "100%", display: "flex", flexDirection: "column" }}>
              {/* section tag (+ level badge in revision) */}
              <div style={{ textAlign: "center", marginBottom: 14, display: "flex", justifyContent: "center", alignItems: "center", gap: 7, flexWrap: "wrap" }}>
                {scope.type === "merged" && card && <span style={lvChip(card.level)}>{card.level}</span>}
                <span
                  style={{
                    fontSize: 10.5,
                    letterSpacing: 1.6,
                    color: C.gold,
                    fontFamily: FJP,
                    border: "1px solid " + hexA(C.gold, 0.3),
                    padding: "3px 10px",
                    borderRadius: 20,
                  }}
                >
                  {SECTIONS[card.si]}
                </span>
              </div>

              {/* prompt block */}
              <div style={{ flex: revealed ? "none" : 1, display: "flex", flexDirection: "column", justifyContent: "center", alignItems: "center" }}>
                {dir === "en" ? (
                  <CopyTarget active={revealed} flash={flash === "meaning"} onTap={() => copyField("meaning", card.meaning)}>
                    <div style={{ fontFamily: FJP, fontWeight: 700, fontSize: 30, color: C.ink, textAlign: "center", lineHeight: 1.25 }}>
                      {card.meaning}
                    </div>
                  </CopyTarget>
                ) : (
                  <CopyTarget
                    active={revealed}
                    flash={flash === "word"}
                    onTap={() => copyField("word", hasKanji ? card.kanji : card.kana)}
                  >
                    <div style={{ fontFamily: FDISP, fontWeight: 700, fontSize: fontForWord(promptWord), color: C.ink, textAlign: "center", lineHeight: 1.15 }}>
                      {promptWord}
                    </div>
                  </CopyTarget>
                )}
                {!revealed && (
                  <div style={{ marginTop: 22, fontSize: 12.5, color: C.faint, fontFamily: FJP, animation: "n5in .4s" }}>
                    {dir === "en" ? "recall the Japanese · tap to reveal" : "tap to reveal"}
                  </div>
                )}
              </div>

              {/* revealed content */}
              {revealed && (
                <div style={{ animation: "n5reveal .3s ease both" }}>
                  {dir === "en" && hasKanji && (
                    <CopyTarget active flash={flash === "kanji"} onTap={() => copyField("kanji", card.kanji)} center>
                      <div style={{ fontFamily: FDISP, fontWeight: 700, fontSize: fontForWord(card.kanji), color: C.ink, textAlign: "center", lineHeight: 1.15, marginTop: 6 }}>
                        {card.kanji}
                      </div>
                    </CopyTarget>
                  )}
                  {dir === "jp" && hasKanji && (
                    <CopyTarget active flash={flash === "kanji"} onTap={() => copyField("kanji", card.kanji)} center>
                      {/* kanji already shown as prompt; keep tappable region but no dup */}
                      <div style={{ display: "none" }} />
                    </CopyTarget>
                  )}

                  {/* reading row */}
                  <div style={{ display: "flex", justifyContent: "center", alignItems: "baseline", gap: 12, flexWrap: "wrap", marginTop: 12 }}>
                    <CopyTarget active flash={flash === "kana"} onTap={() => copyField("kana", card.kana)}>
                      <span style={{ fontFamily: FJP, fontSize: 22, fontWeight: 500, color: C.ink }}>{card.kana}</span>
                    </CopyTarget>
                    <CopyTarget active flash={flash === "romaji"} onTap={() => copyField("romaji", card.romaji)}>
                      <span style={{ fontFamily: FJP, fontSize: 14, color: C.sub, letterSpacing: 0.6 }}>{card.romaji}</span>
                    </CopyTarget>
                  </div>

                  <div style={{ height: 1, background: C.line, margin: "16px 0" }} />

                  {/* meaning (hidden in en since shown as prompt) */}
                  {dir === "jp" && card.meaning && (
                    <CopyTarget active flash={flash === "meaning"} onTap={() => copyField("meaning", card.meaning)} center>
                      <div style={{ fontFamily: FJP, fontWeight: 700, fontSize: 19, color: C.ink, textAlign: "center", lineHeight: 1.3 }}>
                        {card.meaning}
                      </div>
                    </CopyTarget>
                  )}

                  {/* mnemonic / kanji breakdown — editable (markdown override stored per card) */}
                  {(() => {
                    const ov = bdEdits[card.id];
                    const hasContent = ov != null || card.breakdown || card.mnemonic;
                    if (!hasContent)
                      return (
                        <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
                          <button onClick={() => setEditing(card.id)} className="n5press" style={{ ...ghostAdd, width: "auto", marginTop: 0, flex: 1 }}>
                            ✎ Add a breakdown / note
                          </button>
                          <button onClick={() => pasteToCard(card.id)} className="n5press" style={{ ...ghostAdd, width: "auto", marginTop: 0, flex: "0 0 auto", padding: "13px 18px" }} title="Replace this card with clipboard contents">
                            Paste
                          </button>
                        </div>
                      );
                    return (
                      <div
                        style={{
                          marginTop: 14,
                          background: "var(--panel)",
                          border: "1px solid " + C.line,
                          borderRadius: 14,
                          padding: "14px 15px",
                        }}
                      >
                        {ov != null ? (
                          renderMarkdown(ov)
                        ) : card.breakdown ? (
                          <Breakdown b={card.breakdown} />
                        ) : (
                          <>
                            <div style={{ fontSize: 10, letterSpacing: 1.6, color: C.gold, fontFamily: FJP, marginBottom: 6 }}>
                              HINT
                            </div>
                            <div style={{ fontFamily: FJP, fontSize: 15, lineHeight: 1.7, color: C.ink }}>
                              {renderMnemonic(card.mnemonic)}
                            </div>
                          </>
                        )}
                        <div style={{ display: "flex", justifyContent: "flex-end", alignItems: "center", gap: 9, marginTop: 11, borderTop: "1px solid " + C.line, paddingTop: 9 }}>
                          {ov != null && <span style={{ fontSize: 10, color: C.gold, fontFamily: FJP, letterSpacing: 0.5 }}>✎ edited</span>}
                          <button onClick={() => pasteToCard(card.id)} className="n5press" style={bdEditBtn} title="Replace this card with clipboard contents">
                            Paste
                          </button>
                          <button onClick={() => setEditing(card.id)} className="n5press" style={bdEditBtn}>
                            Edit
                          </button>
                        </div>
                      </div>
                    );
                  })()}
                  <div style={{ height: 4 }} />
                </div>
              )}
            </div>
          </div>

          {/* controls (fixed height slot) */}
          {revealed ? (
            scope.type === "merged" ? (
              revMode === "srs" ? (
                srsGradeBar
              ) : (
                <div style={gradeBar}>
                  <button onClick={() => revAdvance(false)} className="n5press" style={revCtl(C.learn, 1)}>
                    <span style={{ fontSize: 18, color: C.learn, lineHeight: 1 }}>↻</span>
                    <span style={{ fontSize: 14, fontWeight: 700, color: C.learn, fontFamily: FDISP }}>
                      Again<span style={{ color: hexA(C.learn, 0.55), fontSize: 11, marginLeft: 6, fontWeight: 700 }} className="n5-kbd-hint">x</span>
                    </span>
                  </button>
                  <button onClick={() => revAdvance(true)} className="n5press" style={{ ...revCtl(C.good, 1.5), background: hexA(C.good, 0.12) }}>
                    <span style={{ fontSize: 18, color: C.good, lineHeight: 1 }}>✓</span>
                    <span style={{ fontSize: 16, fontWeight: 800, color: C.good, fontFamily: FDISP }}>
                      Got it<span style={{ color: hexA(C.good, 0.55), fontSize: 11, marginLeft: 6, fontWeight: 700 }} className="n5-kbd-hint">␣</span>
                    </span>
                  </button>
                </div>
              )
            ) : (
              srsGradeBar
            )
          ) : (
            <div style={{ ...gradeBar, justifyContent: "center", alignItems: "center", borderTop: "1px solid " + C.line }}>
              <button
                onClick={doReveal}
                style={{ background: "none", border: "none", color: C.sub, fontFamily: FJP, fontSize: 14, letterSpacing: 1, cursor: "pointer" }}
              >
                Show answer<span style={{ color: C.faint, fontSize: 11, marginLeft: 7 }} className="n5-kbd-hint">␣</span>
              </button>
            </div>
          )}
        </>
      ) : (
        /* ----- done for now ----- */
        scope.type === "merged" ? (
          revMode === "srs" ? (
            (() => {
              const waiting = revSet.nextDue !== Infinity;
              return (
                <div style={{ flex: 1, minHeight: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "20px 28px", textAlign: "center", animation: "n5pop .3s" }}>
                  <div style={{ width: 64, height: 64, borderRadius: 40, border: "2px solid " + hexA(waiting ? C.seal : C.good, 0.5), display: "grid", placeItems: "center", color: waiting ? C.seal : C.good, fontSize: 30, marginBottom: 18 }}>
                    {waiting ? "⏱" : "✓"}
                  </div>
                  <div style={{ fontFamily: FDISP, fontWeight: 800, fontSize: 22, color: C.ink }}>{waiting ? "Caught up for now" : "Set complete"}</div>
                  <div style={{ fontFamily: FJP, fontSize: 14, color: C.sub, marginTop: 8 }}>
                    <b style={{ color: C.good }}>{revSet.known}</b> learned · {revSet.total} in this set
                  </div>
                  <div style={{ marginTop: 16, fontFamily: FJP, fontSize: 13.5, color: C.faint, lineHeight: 1.6 }}>
                    {waiting ? (
                      <>Next card due {fmtWhen(revSet.nextDue - now)} — it'll reappear automatically.</>
                    ) : (
                      <>You've cleared everything in this set. 🎉</>
                    )}
                  </div>
                  <button onClick={() => setView("home")} style={{ ...moreBtn, background: "transparent", color: C.sub, border: "1px solid " + C.line, marginTop: 18 }}>
                    Back to revision
                  </button>
                </div>
              );
            })()
          ) : (
          (() => {
            const unknown = revQueue.filter((id) => !revKnown[id]).length;
            const got = revQueue.length - unknown;
            return (
              <div style={{ flex: 1, minHeight: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "20px 28px", textAlign: "center", animation: "n5pop .3s" }}>
                <div style={{ width: 64, height: 64, borderRadius: 40, border: "2px solid " + hexA(unknown ? C.seal : C.good, 0.5), display: "grid", placeItems: "center", color: unknown ? C.seal : C.good, fontSize: 30, marginBottom: 18 }}>
                  {unknown ? "↻" : "✓"}
                </div>
                <div style={{ fontFamily: FDISP, fontWeight: 800, fontSize: 22, color: C.ink }}>Revision pass complete</div>
                <div style={{ fontFamily: FJP, fontSize: 14, color: C.sub, marginTop: 8 }}>
                  <b style={{ color: C.good }}>{got}</b> got it · <b style={{ color: unknown ? C.seal : C.faint }}>{unknown}</b> to review · {revQueue.length} total
                </div>
                {unknown > 0 && (
                  <button onClick={() => startRevision(scope.mg, true)} style={moreBtn}>
                    Review the {unknown} you missed
                  </button>
                )}
                <button onClick={() => startRevision(scope.mg, false)} style={{ ...moreBtn, background: unknown ? "transparent" : C.seal, color: unknown ? C.sub : "#fff", border: unknown ? "1px solid " + C.line : "none", marginTop: 10 }}>
                  Revise this set again
                </button>
                <button onClick={() => setView("home")} style={{ ...moreBtn, background: "transparent", color: C.sub, border: "1px solid " + C.line, marginTop: 10 }}>
                  Back to revision
                </button>
              </div>
            );
          })()
          )
        ) : (
          <div style={{ flex: 1, minHeight: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "20px 28px", textAlign: "center", animation: "n5pop .3s" }}>
            <div style={{ width: 64, height: 64, borderRadius: 40, border: "2px solid " + hexA(C.good, 0.5), display: "grid", placeItems: "center", color: C.good, fontSize: 30, marginBottom: 18 }}>
              ✓
            </div>
            <div style={{ fontFamily: FDISP, fontWeight: 800, fontSize: 22, color: C.ink }}>Done for now</div>
            <div style={{ fontFamily: FJP, fontSize: 14, color: C.sub, marginTop: 8 }}>
              {daily.reviewsToday || 0} card{(daily.reviewsToday || 0) === 1 ? "" : "s"} studied today
            </div>
            <div style={{ marginTop: 18, fontFamily: FJP, fontSize: 13.5, color: C.faint, lineHeight: 1.6 }}>
              {nextDue !== Infinity ? (
                <>Next card due {fmtWhen(nextDue - now)}</>
              ) : counters.newLeft > 0 ? (
                <>Daily new-card limit reached.</>
              ) : scope.type === "all" ? (
                <>Every card in the collection has been seen. 🎉</>
              ) : scope.type === "level" ? (
                <>Every {scope.level} card has been introduced. 🎉</>
              ) : (
                <>This section is fully introduced.</>
              )}
            </div>
            {counters.newLeft > 0 && newAllowance <= 0 && (
              <button
                onClick={() => setDaily((d) => ({ ...d, extraNew: (d.extraNew || 0) + 10 }))}
                style={moreBtn}
              >
                + Study 10 more new
              </button>
            )}
            <button onClick={() => setView("home")} style={{ ...moreBtn, background: "transparent", color: C.sub, border: "1px solid " + C.line, marginTop: 10 }}>
              Back to sections
            </button>
          </div>
        )
      )}

      {toast && (
        <div
          key={toast.id}
          style={{
            position: "fixed",
            left: "50%",
            bottom: "calc(100px + env(safe-area-inset-bottom))",
            transform: "translateX(-50%)",
            background: C.ink,
            color: C.bg0,
            fontFamily: FJP,
            fontSize: 13,
            fontWeight: 700,
            padding: "9px 16px",
            borderRadius: 30,
            boxShadow: "0 8px 24px rgba(0,0,0,0.4)",
            animation: "n5toast 1.15s ease forwards",
            maxWidth: "80%",
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
            zIndex: 50,
          }}
        >
          {toast.msg}
        </div>
      )}

      {showSettings && (
        <SettingsSheet
          settings={settings}
          setSettings={setSettings}
          theme={theme}
          setTheme={setTheme}
          stats={stats}
          daily={daily}
          confirmReset={confirmReset}
          setConfirmReset={setConfirmReset}
          onReset={(target) => {
            if (target === "level" || target === "all") {
              setSched({});
              setDaily({ date: todayStr(Date.now()), newDone: 0, reviewsToday: 0, extraNew: 0 });
            }
            if (target === "revision" || target === "all") {
              setRevSched({});
              setRevKnown({});
              setRevQueue([]);
              setRevPos(0);
            }
            setUndoStack([]);
            setCur(null);
            setConfirmReset(false);
            setShowSettings(false);
          }}
          onClose={() => {
            setShowSettings(false);
            setConfirmReset(false);
          }}
          bdEdits={bdEdits}
          setBdEdits={setBdEdits}
          exportBlob={exportBlob}
          onImportData={applyData}
          syncOn={syncOn}
          setSyncOn={setSyncOn}
          syncState={syncState}
        />
      )}

      {editing != null && card && (
        <BreakdownEditor
          title={card.kanji || card.kana}
          initial={bdEdits[card.id] != null ? bdEdits[card.id] : serializeBreakdown(card)}
          hasOverride={bdEdits[card.id] != null}
          onSave={(t) => {
            setBdEdits((m) => ({ ...m, [card.id]: t }));
            setEditing(null);
          }}
          onReset={() => {
            setBdEdits((m) => {
              const n = { ...m };
              delete n[card.id];
              return n;
            });
            setEditing(null);
          }}
          onClose={() => setEditing(null)}
        />
      )}
    </Shell>
  );
}

